AM + AN + MN &= AM + AN + MI + NI \\
&= AM + AN + MB + NC \\
&= (AM + MB) + (AN + NC) \\
&= AB + AC \\
&= 17 + 24 \\
&= \boxed{41}.
\end{align*}

